data.content:
MSTest **does not** have `Assert.IsGreaterThan` or `Assert.IsInRange` as standalone methods in older versions, but **MSTest 3.x+** added these comparison assertions:

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

Here's how to apply them to your `ScoreCalculator`:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        var result = _calc.CalculatePercentage(3, 4);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result); // result > 0
    }

    [TestMethod]
    public void NormalizeScore_CapsAt100()
    {
        var result = _calc.NormalizeScore(150, 100);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(100.1, result); // result < 100.1
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }
}
```

**Key points:**
- `Assert.IsGreaterThan(lowerBound, actual)` — fails if `actual <= lowerBound`
- `Assert.IsLessThan(upperBound, actual)` — fails if `actual >= upperBound`
- `Assert.IsInRange(actual, low, high)` — inclusive range check

These require **MSTest 3.x+** (the `MSTest` metapackage or `MSTest.Sdk`). They produce clear failure messages like `"Expected value to be greater than 0.0, but was 0.0"`.
